//instance-utils.js

import { isObjectPropDefined } from './zcutils';
import { noOperation } from '../core/zc-constants';

/**
 * @param  {Object} thisArg    [description]
 * @param  {String}  methodName [description]
 * @return {Function}             [description]
 */
function getMethodFromInstance(thisArg, methodName) {
    var method = thisArg && isObjectPropDefined(thisArg, methodName, true);

    if (!method) {
        return noOperation;
    }

    return method.bind(thisArg);
}

export { getMethodFromInstance };
